var EFI=window.EFI||{};EFI.Auth=(function(){'use strict';var USERS_KEY='efi_users';var SESSION_KEY='efi_session';var CART_KEY='efi_cart';var PURCHASES_KEY='efi_purchases';var ACCESS_TOKEN_KEY='efi_access_token';var REFRESH_TOKEN_KEY='efi_refresh_token';var ACTION_PLAN_STORAGE_KEY='efi_action_plans_v1';var REFLECTION_STORAGE_KEY='efi_reflections_v1';var ADHERENCE_STORAGE_KEY='efi_adherence_v1';var LEARNING_LOOP_SYNC_MS=15000;var learningLoopSyncTimer=null;var learningLoopSyncBound=false;var lastLearningLoopSignature='';var ACTION_PLAN_STORAGE_KEY='efi_action_plans_v1';var REFLECTION_STORAGE_KEY='efi_reflections_v1';var ADHERENCE_STORAGE_KEY='efi_adherence_v1';function apiFetch(path,opts){if(!window.fetch)return Promise.reject(new Error('Browser does not support fetch.'));var nextOpts=Object.assign({},opts||{});var nextHeaders=Object.assign({},(nextOpts&&nextOpts.headers)||{});var token=getAccessToken();if(token&&!nextHeaders.Authorization&&!nextHeaders.authorization){nextHeaders.Authorization='Bearer '+token;}
nextOpts.headers=nextHeaders;return fetch(path,nextOpts).then(function(res){return res.json().catch(function(){return{};}).then(function(data){if(!res.ok||data.ok===false){throw new Error(data.error||'Request failed');}
return data;});});}
function getAccessToken(){return localStorage.getItem(ACCESS_TOKEN_KEY)||'';}
function setManagedTokens(accessToken,refreshToken){if(accessToken)localStorage.setItem(ACCESS_TOKEN_KEY,accessToken);if(refreshToken)localStorage.setItem(REFRESH_TOKEN_KEY,refreshToken);}
function clearManagedTokens(){localStorage.removeItem(ACCESS_TOKEN_KEY);localStorage.removeItem(REFRESH_TOKEN_KEY);}
function getUsers(){try{return JSON.parse(localStorage.getItem(USERS_KEY))||{};}catch(e){return{};}}
function saveUsers(users){localStorage.setItem(USERS_KEY,JSON.stringify(users));}
function hashPasswordLegacy(pw){var hash=0;for(var i=0;i<pw.length;i++){var ch=pw.charCodeAt(i);hash=((hash<<5)-hash)+ch;hash|=0;}
return'h'+Math.abs(hash).toString(36);}
function bytesToBase64(bytes){var binary='';bytes.forEach(function(b){binary+=String.fromCharCode(b);});return btoa(binary);}
function base64ToBytes(base64){var binary=atob(base64);var bytes=new Uint8Array(binary.length);for(var i=0;i<binary.length;i++)bytes[i]=binary.charCodeAt(i);return bytes;}
async function hashPassword(pw,saltBase64){if(!window.crypto||!window.crypto.subtle){return{algo:'legacy',digest:hashPasswordLegacy(pw)};}
var saltBytes=saltBase64?base64ToBytes(saltBase64):window.crypto.getRandomValues(new Uint8Array(16));var keyMaterial=await window.crypto.subtle.importKey('raw',new TextEncoder().encode(pw),{name:'PBKDF2'},false,['deriveBits']);var derivedBits=await window.crypto.subtle.deriveBits({name:'PBKDF2',salt:saltBytes,iterations:120000,hash:'SHA-256'},keyMaterial,256);return{algo:'pbkdf2-sha256',salt:bytesToBase64(saltBytes),digest:bytesToBase64(new Uint8Array(derivedBits))};}
function getDefaultProgress(){return{modules:{},moduleAssessments:{},esqrCompleted:false,submissions:{},capstone:{status:'not_submitted'},learningLoop:{actionPlans:[],reflections:[],adherence:{sessions:[]}}};}
function readStorageJson(key,fallback){try{var parsed=JSON.parse(localStorage.getItem(key));return parsed||fallback;}catch(e){return fallback;}}
function writeStorageJson(key,value){try{localStorage.setItem(key,JSON.stringify(value));return true;}catch(e){return false;}}
function normalizeProgress(progress){var merged=progress||{};if(!merged.modules)merged.modules={};if(!merged.moduleAssessments)merged.moduleAssessments={};if(!merged.submissions)merged.submissions={};if(!merged.capstone)merged.capstone={status:'not_submitted'};if(!merged.capstone.status)merged.capstone.status='not_submitted';if(typeof merged.esqrCompleted!=='boolean')merged.esqrCompleted=false;if(!merged.learningLoop||typeof merged.learningLoop!=='object')merged.learningLoop={};if(!Array.isArray(merged.learningLoop.actionPlans))merged.learningLoop.actionPlans=[];if(!Array.isArray(merged.learningLoop.reflections))merged.learningLoop.reflections=[];if(!merged.learningLoop.adherence||typeof merged.learningLoop.adherence!=='object'){merged.learningLoop.adherence={sessions:[]};}
if(!Array.isArray(merged.learningLoop.adherence.sessions))merged.learningLoop.adherence.sessions=[];return merged;}
function cloneJson(value,fallback){try{return JSON.parse(JSON.stringify(value));}catch(e){return fallback;}}
function getLearningLoopKey(record,fallbackPrefix,index){if(!record||typeof record!=='object')return fallbackPrefix+'_'+index;if(record.plan_id)return'plan_'+record.plan_id;if(record.id)return'id_'+record.id;if(record.at)return'at_'+record.at;if(record.state&&record.state.created_at)return'created_'+record.state.created_at;return fallbackPrefix+'_'+index+'_'+JSON.stringify(record);}
function mergeLearningLoopCollection(primary,secondary,limit,fallbackPrefix){var merged=[];var seen={};[primary,secondary].forEach(function(list){if(!Array.isArray(list))return;list.forEach(function(item,index){var key=getLearningLoopKey(item,fallbackPrefix,index);if(seen[key])return;seen[key]=true;merged.push(cloneJson(item,item));});});return merged.slice(-limit);}
function buildAdherenceComputed(sessions){var safeSessions=Array.isArray(sessions)?sessions.slice(-30):[];var recent=safeSessions.slice(-10);var doneCount=recent.filter(function(session){return!!(session&&session.completed);}).length;var ratio=recent.length?doneCount/recent.length:0;return{level:ratio>=0.7?'high':(ratio>=0.4?'medium':'low'),score:ratio,sample_size:recent.length};}
function mergeAdherence(primary,secondary){var seen={};var sessions=[];[primary,secondary].forEach(function(item){var list=item&&Array.isArray(item.sessions)?item.sessions:[];list.forEach(function(session,index){var key=getLearningLoopKey(session,'session',index)+'_'+String(!!(session&&session.completed));if(seen[key])return;seen[key]=true;sessions.push(cloneJson(session,session));});});sessions=sessions.slice(-30);return{sessions:sessions,computed:buildAdherenceComputed(sessions)};}
function readLearningLoopFromLocal(){return{actionPlans:readStorageJson(ACTION_PLAN_STORAGE_KEY,[]),reflections:readStorageJson(REFLECTION_STORAGE_KEY,[]),adherence:readStorageJson(ADHERENCE_STORAGE_KEY,{sessions:[]})};}
function mergeLearningLoop(progressArg,localLoopArg){var progress=normalizeProgress(progressArg||getDefaultProgress());var localLoop=localLoopArg||readLearningLoopFromLocal();progress.learningLoop={actionPlans:mergeLearningLoopCollection(progress.learningLoop.actionPlans,localLoop.actionPlans,50,'plan'),reflections:mergeLearningLoopCollection(progress.learningLoop.reflections,localLoop.reflections,100,'reflection'),adherence:mergeAdherence(progress.learningLoop.adherence,localLoop.adherence)};return progress;}
function getLearningLoopSignature(progressArg){var progress=normalizeProgress(progressArg||getDefaultProgress());try{return JSON.stringify(progress.learningLoop||{});}catch(e){return'';}}
function mergeLearningLoopFromLocal(progressArg){return mergeLearningLoop(progressArg,readLearningLoopFromLocal());}
function hydrateLearningLoopToLocal(progressArg){var progress=normalizeProgress(progressArg||getDefaultProgress());if(progress.learningLoop){writeStorageJson(ACTION_PLAN_STORAGE_KEY,(progress.learningLoop.actionPlans||[]).slice(-50));writeStorageJson(REFLECTION_STORAGE_KEY,(progress.learningLoop.reflections||[]).slice(-100));writeStorageJson(ADHERENCE_STORAGE_KEY,progress.learningLoop.adherence||{sessions:[]});}
lastLearningLoopSignature=getLearningLoopSignature(progress);}
function syncLearningLoopState(force){var user=getCurrentUser();if(!user)return false;user.progress=mergeLearningLoopFromLocal(user.progress);if(!force){var signature=getLearningLoopSignature(user.progress);if(signature&&signature===lastLearningLoopSignature)return true;}
return updateUser({progress:user.progress});}
function startLearningLoopSync(){if(learningLoopSyncTimer)return;learningLoopSyncTimer=window.setInterval(function(){if(!isLoggedIn())return;syncLearningLoopState(false);},LEARNING_LOOP_SYNC_MS);}
function bindLearningLoopSyncEvents(){if(learningLoopSyncBound)return;learningLoopSyncBound=true;window.addEventListener('beforeunload',function(){if(!isLoggedIn())return;syncLearningLoopState(true);});document.addEventListener('visibilitychange',function(){if(document.visibilityState!=='hidden'||!isLoggedIn())return;syncLearningLoopState(true);});}
function normalizeModuleId(moduleId){var raw=String(moduleId||'').trim();if(!raw)return'';var match=raw.match(/module-(\d+)/);if(match)return match[1];return raw.replace(/[^\d]/g,'');}
function getModuleAssessment(moduleId,progressArg){var progress=normalizeProgress(progressArg||(getCurrentUser()&&getCurrentUser().progress)||getDefaultProgress());var key=normalizeModuleId(moduleId);if(!key)return null;return progress.moduleAssessments[key]||null;}
function isModuleComplete(moduleId,progressArg){var progress=normalizeProgress(progressArg||(getCurrentUser()&&getCurrentUser().progress)||getDefaultProgress());var key=normalizeModuleId(moduleId);if(!key)return false;var assessment=progress.moduleAssessments[key];if(assessment&&assessment.passed)return true;return!!progress.modules[key];}
function recordModuleAssessment(moduleId,result){var user=getCurrentUser();if(!user){return{ok:false,error:'Please log in to save your module test result.'};}
user.progress=normalizeProgress(user.progress);var key=normalizeModuleId(moduleId);if(!key){return{ok:false,error:'A valid module ID is required.'};}
var score=Number(result&&result.score);var total=Number(result&&result.total);var correct=Number(result&&result.correct);var percentage=Number.isFinite(score)?Math.max(0,Math.min(100,Math.round(score))):0;var passed=!!(result&&result.passed);var now=new Date().toISOString();user.progress.moduleAssessments[key]={moduleId:key,score:percentage,correct:Number.isFinite(correct)?correct:0,total:Number.isFinite(total)&&total>0?total:0,passed:passed,completedAt:now,savedAt:now};user.progress.modules[key]=passed;updateUser({progress:user.progress});return{ok:true,assessment:user.progress.moduleAssessments[key],progress:user.progress,status:getCertificationStatus(user)};}
async function register(name,email,password){try{var managed=await apiFetch('/api/auth',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'register',name:name,email:email,password:password})});if(managed&&managed.ok&&managed.user){setManagedTokens(managed.access_token||'',managed.refresh_token||'');var managedProgress=mergeLearningLoopFromLocal(managed.user.progress||getDefaultProgress());hydrateLearningLoopToLocal(managedProgress);setSession({email:managed.user.email,name:managed.user.name||managed.user.email,mode:'managed',role:managed.user.role||'learner',createdAt:managed.user.createdAt||new Date().toISOString(),progress:managedProgress,purchases:managed.user.purchases||[]});syncLearningLoopState(true);return{ok:true,user:getCurrentUser()};}}catch(managedErr){}
var users=getUsers();var key=email.toLowerCase().trim();if(users[key]){return{ok:false,error:'An account with this email already exists.'};}
if(password.length<6){return{ok:false,error:'Password must be at least 6 characters.'};}
var hashed=await hashPassword(password);users[key]={name:name.trim(),email:key,role:'learner',passwordHash:hashed.digest,passwordSalt:hashed.salt||null,passwordAlgo:hashed.algo,createdAt:new Date().toISOString(),progress:getDefaultProgress(),purchases:[]};saveUsers(users);hydrateLearningLoopToLocal(users[key].progress);setSession(users[key]);apiFetch('/api/sync-progress',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:key,progress:users[key].progress})}).catch(function(){});return{ok:true,user:users[key]};}
async function login(email,password){try{var managed=await apiFetch('/api/auth',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'login',email:email,password:password})});if(managed&&managed.ok&&managed.user){setManagedTokens(managed.access_token||'',managed.refresh_token||'');var managedProgress=mergeLearningLoopFromLocal(managed.user.progress||getDefaultProgress());hydrateLearningLoopToLocal(managedProgress);setSession({email:managed.user.email,name:managed.user.name||managed.user.email,mode:'managed',role:managed.user.role||'learner',createdAt:managed.user.createdAt||new Date().toISOString(),progress:managedProgress,purchases:managed.user.purchases||[]});syncLearningLoopState(true);return{ok:true,user:getCurrentUser()};}}catch(managedErr){}
var users=getUsers();var key=email.toLowerCase().trim();var user=users[key];if(!user){return{ok:false,error:'No account found with this email address.'};}
var isValid=false;if((user.passwordAlgo||'legacy')==='pbkdf2-sha256'){var hashed=await hashPassword(password,user.passwordSalt);isValid=hashed.digest===user.passwordHash;}else{isValid=hashPasswordLegacy(password)===user.passwordHash;if(isValid){var migrated=await hashPassword(password);user.passwordHash=migrated.digest;user.passwordSalt=migrated.salt||null;user.passwordAlgo=migrated.algo;users[key]=user;saveUsers(users);}}
if(!isValid){return{ok:false,error:'Incorrect password. Please try again.'};}
apiFetch('/api/sync-progress?email='+encodeURIComponent(key)).then(function(remote){if(remote&&remote.ok&&remote.progress){user.progress=mergeLearningLoopFromLocal(remote.progress);users[key]=user;saveUsers(users);hydrateLearningLoopToLocal(user.progress);setSession(user);syncLearningLoopState(true);}}).catch(function(){});hydrateLearningLoopToLocal(user.progress||getDefaultProgress());setSession(user);return{ok:true,user:user};}
function logout(){var token=getAccessToken();if(token){apiFetch('/api/auth',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'logout',access_token:token})}).catch(function(){});}
clearManagedTokens();localStorage.removeItem(SESSION_KEY);window.location.href='login.html';}
function setSession(user){localStorage.setItem(SESSION_KEY,JSON.stringify({email:user.email,name:user.name,mode:user.mode||'prototype',role:user.role||'learner',createdAt:user.createdAt||new Date().toISOString(),progress:user.progress||getDefaultProgress(),purchases:user.purchases||[],loggedInAt:new Date().toISOString()}));}
function getSession(){try{return JSON.parse(localStorage.getItem(SESSION_KEY));}catch(e){return null;}}
function getCurrentUser(){var session=getSession();if(!session)return null;if(session.mode==='managed'){var managedUser={name:session.name,email:session.email,role:session.role||'learner',createdAt:session.createdAt||session.loggedInAt,progress:normalizeProgress(session.progress||getDefaultProgress()),purchases:Array.isArray(session.purchases)?session.purchases:[]};return managedUser;}
var users=getUsers();var user=users[session.email]||null;if(user&&!user.role)user.role='learner';if(user&&user.progress)user.progress=normalizeProgress(user.progress);return user;}
function getRole(){var user=getCurrentUser();return user?(user.role||'learner'):'guest';}
function hasRole(roles){var role=getRole();if(!Array.isArray(roles))roles=[roles];return roles.indexOf(role)!==-1;}
function requireRole(roles,redirectPath){if(!requireAuth())return false;if(hasRole(roles))return true;window.location.href=redirectPath||'dashboard.html';return false;}
function exportPrototypeData(){return{users:getUsers(),session:getSession(),cart:getCart(),exportedAt:new Date().toISOString(),version:1};}
function importPrototypeData(payload){if(!payload||typeof payload!=='object'){return{ok:false,error:'Invalid import payload.'};}
if(payload.users&&typeof payload.users==='object'){localStorage.setItem(USERS_KEY,JSON.stringify(payload.users));}
if(payload.session&&typeof payload.session==='object'){localStorage.setItem(SESSION_KEY,JSON.stringify(payload.session));}
if(Array.isArray(payload.cart)){localStorage.setItem(CART_KEY,JSON.stringify(payload.cart));}
updateCartBadge();return{ok:true};}
function resetPrototypeData(){localStorage.removeItem(USERS_KEY);localStorage.removeItem(SESSION_KEY);localStorage.removeItem(CART_KEY);localStorage.removeItem('efi_esqr_results');localStorage.removeItem('efi_esqr_history');localStorage.removeItem('efi_client_errors');return{ok:true};}
function updateUser(updates){var session=getSession();if(!session)return false;if(session.mode==='managed'){var nextProgress=updates&&updates.progress?mergeLearningLoopFromLocal(updates.progress):mergeLearningLoopFromLocal(session.progress||getDefaultProgress());var next={email:session.email,name:updates&&updates.name?updates.name:session.name,mode:'managed',role:session.role||'learner',createdAt:session.createdAt||new Date().toISOString(),progress:nextProgress,purchases:updates&&updates.purchases?updates.purchases:(session.purchases||[])};setSession(next);hydrateLearningLoopToLocal(next.progress);if(next.progress){apiFetch('/api/sync-progress',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:next.email,progress:next.progress})}).catch(function(){});}
return true;}
var users=getUsers();var user=users[session.email];if(!user)return false;for(var key in updates){if(updates.hasOwnProperty(key)){user[key]=updates[key];}}
if(updates&&updates.progress){user.progress=mergeLearningLoopFromLocal(updates.progress);}
users[session.email]=user;saveUsers(users);setSession({email:user.email,name:user.name,mode:session.mode||'prototype',role:user.role||'learner',createdAt:user.createdAt||session.createdAt||new Date().toISOString(),progress:user.progress||getDefaultProgress(),purchases:user.purchases||[]});if(user.progress){hydrateLearningLoopToLocal(user.progress);}
if(updates&&updates.progress){apiFetch('/api/sync-progress',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:user.email,progress:user.progress})}).catch(function(){});}
return true;}
function isLoggedIn(){return getSession()!==null;}
function requireAuth(){if(!isLoggedIn()){var current=window.location.pathname.split('/').pop();window.location.href='login.html?redirect='+encodeURIComponent(current);return false;}
return true;}
function getCart(){try{return JSON.parse(localStorage.getItem(CART_KEY))||[];}catch(e){return[];}}
function addToCart(item){if(!item||!item.id)return getCart();if(item.id==='certificate'||item.id==='certificate-frame'){var status=getCertificationStatus();if(!status.eligibleForCertificate)return getCart();}
var cart=getCart();var exists=cart.some(function(c){return c.id===item.id;});if(exists)return cart;cart.push(item);localStorage.setItem(CART_KEY,JSON.stringify(cart));updateCartBadge();return cart;}
function removeFromCart(itemId){var cart=getCart().filter(function(c){return c.id!==itemId;});localStorage.setItem(CART_KEY,JSON.stringify(cart));updateCartBadge();return cart;}
function clearCart(){localStorage.setItem(CART_KEY,JSON.stringify([]));updateCartBadge();}
function getCartTotal(){return getCart().reduce(function(sum,item){return sum+item.price;},0);}
function updateCartBadge(){var badges=document.querySelectorAll('.cart-badge');var count=getCart().length;badges.forEach(function(badge){badge.textContent=count;badge.style.display=count>0?'inline-flex':'none';});}
function getPurchases(){var user=getCurrentUser();return user?(user.purchases||[]):[];}
function addPurchase(items){var user=getCurrentUser();if(!user)return Promise.reject(new Error('Please log in first.'));return apiFetch('/api/verify',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'issue_purchase',email:user.email,items:items})}).then(function(res){var purchase=res.purchase||{id:'ord-'+Date.now().toString(36),date:new Date().toISOString(),items:items,total:items.reduce(function(s,i){return s+i.price;},0)};purchase.receipt=res.receipt||null;purchase.credentialId=res.credential_id||null;var purchases=user.purchases||[];purchases.push(purchase);updateUser({purchases:purchases});clearCart();return purchase;});}
function addOfferPurchase(offer,paymentIntentId,purchaseEmail){var user=getCurrentUser();if(!user)return Promise.reject(new Error('Please log in first.'));var email=String(purchaseEmail||user.email||'').trim().toLowerCase();if(!email||email!==String(user.email||'').trim().toLowerCase()){return Promise.reject(new Error('Log in with the purchasing email to finalize this checkout.'));}
return apiFetch('/api/verify',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'issue_purchase',email:email,offer:offer,payment_intent_id:paymentIntentId})}).then(function(res){var purchase=res.purchase||null;if(!purchase)throw new Error('Purchase record could not be created.');purchase.receipt=res.receipt||purchase.receipt||null;purchase.credentialId=res.credential_id||purchase.credentialId||null;var purchases=user.purchases||[];var alreadyExists=purchases.some(function(entry){return String(entry.id||'')===String(purchase.id||'');});if(!alreadyExists){purchases.push(purchase);}
updateUser({purchases:purchases});return purchase;});}
function hasPurchased(productId){var purchases=getPurchases();return purchases.some(function(p){return p.items.some(function(item){return item.id===productId;});});}
function getLatestReceiptFor(productId){var purchases=getPurchases();var token=null;purchases.forEach(function(p){var match=(p.items||[]).some(function(item){return item.id===productId;});if(match&&p.receipt)token=p.receipt;});return token;}
function verifyPurchasedProduct(productId,credentialId){var receipt=getLatestReceiptFor(productId);if(!receipt)return Promise.resolve({ok:false,verified:false,error:'No signed purchase receipt found.'});var qs='?receipt='+encodeURIComponent(receipt)+'&product='+encodeURIComponent(productId);if(credentialId)qs+='&credential_id='+encodeURIComponent(credentialId);return apiFetch('/api/verify'+qs,{method:'GET'}).catch(function(err){return{ok:false,verified:false,error:err.message};});}
function getCertificationStatus(userArg){var user=userArg||getCurrentUser();if(!user){return{modulesCompleted:0,allModulesCompleted:false,capstonePassed:false,certificatePurchased:false,framedCertificatePurchased:false,eligibleForCertificate:false,fullyCertified:false};}
user.progress=normalizeProgress(user.progress);var moduleIds=['1','2','3','4','5','6'];var modulesCompleted=moduleIds.filter(function(id){return isModuleComplete(id,user.progress);}).length;var allModulesCompleted=modulesCompleted===moduleIds.length;var capstonePassed=user.progress.capstone.status==='passed';var certificatePurchased=(user.purchases||[]).some(function(p){return p.items.some(function(i){return i.id==='certificate';});});var framedCertificatePurchased=(user.purchases||[]).some(function(p){return p.items.some(function(i){return i.id==='certificate-frame';});});var eligibleForCertificate=allModulesCompleted&&capstonePassed;return{modulesCompleted:modulesCompleted,allModulesCompleted:allModulesCompleted,capstonePassed:capstonePassed,certificatePurchased:certificatePurchased,framedCertificatePurchased:framedCertificatePurchased,eligibleForCertificate:eligibleForCertificate,fullyCertified:eligibleForCertificate&&certificatePurchased};}
function getReleaseMetrics(progressArg){var progress=normalizeProgress(progressArg||(getCurrentUser()&&getCurrentUser().progress)||getDefaultProgress());var pending=0;var releaseTimes=[];var scores=[];Object.keys(progress.submissions||{}).forEach(function(key){var row=progress.submissions[key]||{};if(typeof row.score==='number')scores.push(row.score);if(row.releaseAt){var time=new Date(row.releaseAt).getTime();if(time>Date.now()){pending+=1;releaseTimes.push(time);}}});if(progress.capstone&&progress.capstone.releaseAt){var capstoneTime=new Date(progress.capstone.releaseAt).getTime();if(capstoneTime>Date.now()){pending+=1;releaseTimes.push(capstoneTime);}}
releaseTimes.sort(function(a,b){return a-b;});return{pendingReleaseCount:pending,nextReleaseAt:releaseTimes.length?new Date(releaseTimes[0]).toISOString():null,averageScore:scores.length?Math.round(scores.reduce(function(a,b){return a+b;},0)/scores.length):null};}
function submitCapstone(evidenceUrl,notes){var user=getCurrentUser();if(!user)return Promise.resolve({ok:false,error:'Please log in first.'});return apiFetch('/api/submissions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'submit_capstone',email:user.email,evidence_url:(evidenceUrl||'').trim(),notes:(notes||'').trim()})}).then(function(res){user.progress=normalizeProgress(user.progress);user.progress.capstone={status:'feedback_pending_release',submittedAt:new Date().toISOString(),evidenceUrl:(evidenceUrl||'').trim(),notes:(notes||'').trim(),releaseAt:res.release_at};updateUser({progress:user.progress});return{ok:true,capstone:user.progress.capstone,release_at:res.release_at};}).catch(function(err){return{ok:false,error:err.message};});}
function runAutoGrading(){var user=getCurrentUser();if(!user)return Promise.resolve({ok:false,error:'Please log in first.'});return apiFetch('/api/submissions?email='+encodeURIComponent(user.email),{method:'GET'}).then(function(res){user.progress=normalizeProgress(user.progress);(res.submissions||[]).forEach(function(submission){if(submission.kind==='module'&&submission.module_id){user.progress.submissions[String(submission.module_id)]={status:submission.status,submittedAt:submission.submitted_at,evidenceUrl:submission.evidence_url,notes:submission.notes,releaseAt:submission.release_at,score:submission.score,feedback:submission.feedback};if(submission.feedback_available&&typeof submission.score==='number'){var moduleKey=String(submission.module_id);var passed=submission.score>=75;user.progress.modules[moduleKey]=passed;user.progress.moduleAssessments[moduleKey]={moduleId:moduleKey,score:submission.score,correct:null,total:null,passed:passed,completedAt:submission.release_at||submission.submitted_at,savedAt:new Date().toISOString(),source:'submission'};}}
if(submission.kind==='capstone'){user.progress.capstone={status:submission.feedback_available?(submission.score>=75?'passed':'needs-revision'):'feedback_pending_release',submittedAt:submission.submitted_at,releaseAt:submission.release_at,score:submission.score,feedback:submission.feedback};}});updateUser({progress:user.progress});return{ok:true,progress:user.progress,status:getCertificationStatus(user)};}).catch(function(err){return{ok:false,error:err.message};});}
function saveModuleSubmission(moduleId,evidenceUrl,notes){var user=getCurrentUser();if(!user)return Promise.resolve({ok:false,error:'Please log in first.'});return apiFetch('/api/submissions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'submit_module',email:user.email,module_id:String(moduleId),evidence_url:(evidenceUrl||'').trim(),notes:(notes||'').trim()})}).then(function(res){user.progress=normalizeProgress(user.progress);var key=String(moduleId);user.progress.submissions[key]={status:'feedback_pending_release',submittedAt:new Date().toISOString(),evidenceUrl:(evidenceUrl||'').trim(),notes:(notes||'').trim(),releaseAt:res.release_at};updateUser({progress:user.progress});return{ok:true,submission:user.progress.submissions[key],release_at:res.release_at};}).catch(function(err){return{ok:false,error:err.message};});}
function clearNode(node){while(node&&node.firstChild)node.removeChild(node.firstChild);}
function appendNavLink(container,href,label){var link=document.createElement('a');link.href=href;link.className='nav__link';link.textContent=label;container.appendChild(link);}
function initNavAuth(){var session=getSession();var authLinks=document.querySelectorAll('.nav__auth');authLinks.forEach(function(el){clearNode(el);if(session){var user=getCurrentUser();appendNavLink(el,'dashboard.html','Dashboard');if(user&&(user.role==='admin'||user.role==='reviewer')){appendNavLink(el,'admin.html','Admin');}}else{appendNavLink(el,'login.html','Login');}
updateCartBadge();});if(window.EFI&&typeof window.EFI.highlightActiveNavLinks==='function'){window.EFI.highlightActiveNavLinks();}}
function refreshManagedSession(){var session=getSession();var token=getAccessToken();if(!session||session.mode!=='managed'||!token)return Promise.resolve();return apiFetch('/api/auth?action=me',{method:'GET',headers:{Authorization:'Bearer '+token}}).then(function(res){if(!res||!res.ok||!res.user)return;setSession({email:res.user.email,name:res.user.name||res.user.email,mode:'managed',role:res.user.role||'learner',createdAt:res.user.createdAt||session.createdAt,progress:normalizeProgress(res.user.progress||session.progress||getDefaultProgress()),purchases:res.user.purchases||session.purchases||[]});hydrateLearningLoopToLocal(res.user.progress||session.progress||getDefaultProgress());}).catch(function(){});}
document.addEventListener('DOMContentLoaded',function(){var existingUser=getCurrentUser();if(existingUser&&existingUser.progress){hydrateLearningLoopToLocal(existingUser.progress);}
bindLearningLoopSyncEvents();startLearningLoopSync();refreshManagedSession().finally(function(){initNavAuth();updateCartBadge();});});return{register:register,login:login,logout:logout,getSession:getSession,getCurrentUser:getCurrentUser,getUser:getCurrentUser,updateUser:updateUser,syncLearningLoopState:syncLearningLoopState,isLoggedIn:isLoggedIn,requireAuth:requireAuth,getCart:getCart,addToCart:addToCart,removeFromCart:removeFromCart,clearCart:clearCart,getCartTotal:getCartTotal,getPurchases:getPurchases,addPurchase:addPurchase,addOfferPurchase:addOfferPurchase,hasPurchased:hasPurchased,getLatestReceiptFor:getLatestReceiptFor,verifyPurchasedProduct:verifyPurchasedProduct,getCertificationStatus:getCertificationStatus,getReleaseMetrics:getReleaseMetrics,submitCapstone:submitCapstone,runAutoGrading:runAutoGrading,saveModuleSubmission:saveModuleSubmission,recordModuleAssessment:recordModuleAssessment,getModuleAssessment:getModuleAssessment,isModuleComplete:isModuleComplete,getRole:getRole,hasRole:hasRole,requireRole:requireRole,exportPrototypeData:exportPrototypeData,importPrototypeData:importPrototypeData,resetPrototypeData:resetPrototypeData,refreshManagedSession:refreshManagedSession,getAccessToken:getAccessToken};})();window.EFI=EFI;